import{bQ as a,aL as s,u as d,G as e}from"./chunks/framework.D06dwy5q.js";const r="/kb/assets/01-stack-by-layers.BLkfsizt.png",i="/kb/assets/02-storage-by-data-shape.DqoACcLq.png",n="/kb/assets/03-cache-mq-async.DyljrktT.png",l="/kb/assets/04-stack-evolution.Chog_yKG.png",E=JSON.parse('{"title":"第 13 讲｜常见技术栈","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/13-常见技术栈.md","filePath":"00.互联网与架构基础/13-常见技术栈.md","lastUpdated":null}'),o={name:"00.互联网与架构基础/13-常见技术栈.md"};function p(h,t,c,g,u,b){return s(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="第-13-讲-常见技术栈" tabindex="-1">第 13 讲｜常见技术栈 <a class="header-anchor" href="#第-13-讲-常见技术栈" aria-label="Permalink to &quot;第 13 讲｜常见技术栈&quot;">​</a></h1><p>打开任意一个稍复杂的 Web 系统架构图,会看到一组组件名:Vue、React、FastAPI、Spring Boot、MySQL、Redis、Kafka、Nginx、Prometheus、Grafana……第一次接触很容易眼花。</p><p>这些组件不是平铺在一起的工具清单,而是<strong>各自占据系统的某一层</strong>:页面、接口、数据、入口、发布、观测。<strong>理解技术栈的关键是先看每个组件在系统里站哪一层</strong>——页面谁渲染、接口谁提供、数据放哪、异步任务怎么跑、外部请求从哪进、出问题去哪看。把这些位置关系理清,后面接触任何新组件都能快速归类。</p><p>本讲按系统的层次结构,梳理每一层的主流技术选择、适用场景、选型考量。</p><h2 id="一、按层次理解技术栈" tabindex="-1">一、按层次理解技术栈 <a class="header-anchor" href="#一、按层次理解技术栈" aria-label="Permalink to &quot;一、按层次理解技术栈&quot;">​</a></h2><p>一个典型 Web 系统的完整技术栈分层:</p><p><img src="'+r+`" alt="技术栈要按页面接口数据入口观测等层次理解"></p><div class="mermaid-diagram" data-mermaid-code="flowchart%20TB%0A%20%20%20%20Browser%5B%22%E6%B5%8F%E8%A7%88%E5%99%A8%22%5D%0A%20%20%20%20subgraph%20%E5%85%A5%E5%8F%A3%E5%B1%82%0A%20%20%20%20%20%20CDN%5B%22CDN%22%5D%0A%20%20%20%20%20%20LB%5B%22%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%22%5D%0A%20%20%20%20%20%20Ingress%5B%22Nginx%20%2F%20Ingress%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E5%89%8D%E7%AB%AF%0A%20%20%20%20%20%20Static%5B%22%E9%9D%99%E6%80%81%E8%B5%84%E6%BA%90%3Cbr%2F%3EHTML%20%2F%20CSS%20%2F%20JS%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E5%90%8E%E7%AB%AF%0A%20%20%20%20%20%20App%5B%22%E5%BA%94%E7%94%A8%E6%9C%8D%E5%8A%A1%3Cbr%2F%3ESpring%20%2F%20FastAPI%20%2F%20Go%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E6%95%B0%E6%8D%AE%E5%B1%82%0A%20%20%20%20%20%20RDS%5B(%22MySQL%20%2F%20PostgreSQL%22)%5D%0A%20%20%20%20%20%20Cache%5B(%22Redis%22)%5D%0A%20%20%20%20%20%20ES%5B(%22Elasticsearch%22)%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E5%BC%82%E6%AD%A5%E5%B1%82%0A%20%20%20%20%20%20MQ%5B%22%E6%B6%88%E6%81%AF%E9%98%9F%E5%88%97%3Cbr%2F%3EKafka%20%2F%20RabbitMQ%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E5%AD%98%E5%82%A8%0A%20%20%20%20%20%20OSS%5B%22%E5%AF%B9%E8%B1%A1%E5%AD%98%E5%82%A8%3Cbr%2F%3ES3%20%2F%20OSS%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E5%8F%AF%E8%A7%82%E6%B5%8B%0A%20%20%20%20%20%20Prom%5B%22Prometheus%22%5D%0A%20%20%20%20%20%20Loki%5B%22Loki%20%2F%20ELK%22%5D%0A%20%20%20%20%20%20Jaeger%5B%22Jaeger%20%2F%20SkyWalking%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E5%8F%91%E5%B8%83%0A%20%20%20%20%20%20CI%5B%22GitLab%20CI%22%5D%0A%20%20%20%20%20%20Reg%5B%22Harbor%22%5D%0A%20%20%20%20%20%20K8s%5B%22Kubernetes%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20Browser%20--%3E%20CDN%20--%3E%20LB%20--%3E%20Ingress%0A%20%20%20%20Ingress%20--%3E%20Static%0A%20%20%20%20Ingress%20--%3E%20App%0A%20%20%20%20App%20--%3E%20RDS%0A%20%20%20%20App%20--%3E%20Cache%0A%20%20%20%20App%20--%3E%20MQ%0A%20%20%20%20App%20--%3E%20ES%0A%20%20%20%20App%20--%3E%20OSS%0A%20%20%20%20App%20-.-%3E%20Prom%0A%20%20%20%20App%20-.-%3E%20Loki%0A%20%20%20%20App%20-.-%3E%20Jaeger%0A%20%20%20%20CI%20--%3E%20Reg%20--%3E%20K8s%0A"></div><p>接下来逐层讲清楚每一层的主流选择。</p><h2 id="二、页面层-前端" tabindex="-1">二、页面层(前端) <a class="header-anchor" href="#二、页面层-前端" aria-label="Permalink to &quot;二、页面层(前端)&quot;">​</a></h2><p>前端负责<strong>浏览器内的页面结构、样式、交互、调用后端接口</strong>。最终在浏览器中加载的就是 HTML、CSS、JavaScript、图片、字体。</p><h3 id="主流技术分类" tabindex="-1">主流技术分类 <a class="header-anchor" href="#主流技术分类" aria-label="Permalink to &quot;主流技术分类&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>主流选择</th><th>在系统中的位置</th></tr></thead><tbody><tr><td>基础能力</td><td>HTML、CSS、JavaScript</td><td>浏览器原生支持,所有前端最终跑这三样</td></tr><tr><td>框架</td><td>Vue、React、Angular</td><td>组件化开发、状态管理、路由</td></tr><tr><td>构建工具</td><td>Vite、Webpack、esbuild</td><td>把 Vue/JSX/TS 编译为浏览器可执行的 JS</td></tr><tr><td>UI 组件库</td><td>Element Plus、Ant Design、Naive UI、Tailwind</td><td>现成的表单、表格、弹窗、布局</td></tr><tr><td>状态管理</td><td>Pinia、Redux、Zustand</td><td>跨组件共享状态</td></tr><tr><td>路由</td><td>Vue Router、React Router</td><td>SPA 内部页面跳转</td></tr></tbody></table><h3 id="框架选择的现状" tabindex="-1">框架选择的现状 <a class="header-anchor" href="#框架选择的现状" aria-label="Permalink to &quot;框架选择的现状&quot;">​</a></h3><table tabindex="0"><thead><tr><th>框架</th><th>国内</th><th>海外 / 国际</th></tr></thead><tbody><tr><td>Vue</td><td>国内主流(简洁、文档好、上手快)</td><td>较少使用</td></tr><tr><td>React</td><td>大厂主流(生态最庞大、招聘多)</td><td>全球主流</td></tr><tr><td>Angular</td><td>较少</td><td>企业级项目较多</td></tr><tr><td>Svelte / Solid</td><td>新兴,较少</td><td>新兴,增长快</td></tr></tbody></table><p>技术框架选择的现实考量:<strong>团队熟悉度 &gt; 招聘市场 &gt; 技术本身</strong>。各主流框架在能力上没有质的差距,Vue/React 都能胜任绝大多数业务,选哪个更多看团队基础。</p><h3 id="何时不需要前端框架" tabindex="-1">何时不需要前端框架 <a class="header-anchor" href="#何时不需要前端框架" aria-label="Permalink to &quot;何时不需要前端框架&quot;">​</a></h3><p>简单场景下,<strong>原生 HTML/CSS/JS 完全够用</strong>,不必上框架:</p><ul><li>静态展示页面</li><li>简单表单</li><li>内部小工具</li><li>静态文档站</li></ul><p>引入 Vue/React 会增加构建复杂度、学习成本、首屏加载体积。<strong>框架是为复杂交互而设计的</strong>,不是为了&quot;显得现代化&quot;。</p><h3 id="前后端的连接点-http-api" tabindex="-1">前后端的连接点:HTTP API <a class="header-anchor" href="#前后端的连接点-http-api" aria-label="Permalink to &quot;前后端的连接点:HTTP API&quot;">​</a></h3><p>前端代码通过 <code>fetch</code>、<code>axios</code> 调用后端 API:</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fetch</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;/api/users/me&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  headers: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Authorization&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\`Bearer \${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">token</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  .</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">then</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">res</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> res.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">json</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">())</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  .</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">then</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> renderProfile</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(user));</span></span></code></pre></div><p>后端返回 JSON,前端拿到后渲染页面。这就是前后端分离的核心交互模式。</p><h3 id="前端的发布" tabindex="-1">前端的发布 <a class="header-anchor" href="#前端的发布" aria-label="Permalink to &quot;前端的发布&quot;">​</a></h3><p>前端构建后产出的静态文件(HTML / CSS / JS / 图片),可以部署在:</p><ul><li><strong>CDN</strong>:全球加速,主流选择</li><li><strong>对象存储 + CDN</strong>:OSS/S3 作为源站,CDN 缓存分发</li><li><strong>Nginx</strong>:简单场景,适合内部系统</li><li><strong>边缘平台</strong>:Cloudflare Pages、Vercel、Netlify</li></ul><h2 id="三、接口层-后端" tabindex="-1">三、接口层(后端) <a class="header-anchor" href="#三、接口层-后端" aria-label="Permalink to &quot;三、接口层(后端)&quot;">​</a></h2><p>后端负责<strong>HTTP 接口、业务逻辑、认证权限、数据库读写、调用外部系统</strong>。</p><h3 id="主流语言与框架" tabindex="-1">主流语言与框架 <a class="header-anchor" href="#主流语言与框架" aria-label="Permalink to &quot;主流语言与框架&quot;">​</a></h3><table tabindex="0"><thead><tr><th>语言</th><th>主流框架</th><th>适用场景</th></tr></thead><tbody><tr><td>Java</td><td>Spring Boot、Spring Cloud、Quarkus</td><td>国内大厂核心业务、企业级微服务</td></tr><tr><td>Python</td><td>FastAPI、Django、Flask</td><td>运维平台、内部工具、数据处理、AI 应用</td></tr><tr><td>Go</td><td>Gin、Echo、Fiber、net/http</td><td>云原生组件、API 网关、高并发服务</td></tr><tr><td>Node.js</td><td>Express、NestJS、Koa、Fastify</td><td>BFF、轻量 API、与前端 JS 同栈</td></tr><tr><td>.NET</td><td>ASP.NET Core</td><td>Windows 生态、企业系统</td></tr><tr><td>Rust</td><td>Actix、Axum</td><td>极致性能、新兴选择</td></tr><tr><td>Ruby</td><td>Rails</td><td>国外创业公司、快速原型</td></tr><tr><td>PHP</td><td>Laravel、Symfony</td><td>传统 Web、内容管理系统</td></tr></tbody></table><h3 id="各语言的适用边界" tabindex="-1">各语言的适用边界 <a class="header-anchor" href="#各语言的适用边界" aria-label="Permalink to &quot;各语言的适用边界&quot;">​</a></h3><ul><li><strong>Java</strong> — 生态最完整,招人最容易,大厂核心业务首选。劣势:启动慢、内存占用高、入门曲线陡</li><li><strong>Python</strong> — 开发快、可读性好,数据处理与 AI 生态独一无二。劣势:运行性能中等</li><li><strong>Go</strong> — 编译为单个二进制,部署极简,适合云原生(K8s、Docker、Prometheus 全家桶都是 Go)。劣势:错误处理冗长、泛型较新</li><li><strong>Node.js</strong> — 与前端 JS 同语言,前端团队能顺手做后端。劣势:CPU 密集型不擅长</li><li><strong>Rust</strong> — 性能与安全极致,新兴增长。劣势:学习曲线陡</li></ul><p><strong>语言选择的决定性因素是团队基础,不是语言本身的&quot;优劣&quot;</strong>。</p><h3 id="后端不只是几个路由函数" tabindex="-1">后端不只是几个路由函数 <a class="header-anchor" href="#后端不只是几个路由函数" aria-label="Permalink to &quot;后端不只是几个路由函数&quot;">​</a></h3><p>新手容易以为&quot;后端就是写几个路由 + SQL&quot;。真实生产级后端要处理的非业务代码往往比业务代码还多:</p><table tabindex="0"><thead><tr><th>模块</th><th>作用</th></tr></thead><tbody><tr><td>配置管理</td><td>多环境、热更新、敏感信息加密</td></tr><tr><td>数据库连接池</td><td>连接复用、健康检查、连接数控制</td></tr><tr><td>HTTP 客户端</td><td>超时、重试、连接池、TLS</td></tr><tr><td>统一错误处理</td><td>异常 → 标准响应格式</td></tr><tr><td>中间件</td><td>认证、限流、日志、CORS</td></tr><tr><td>优雅关闭</td><td>收到信号后处理完已有请求再退出</td></tr><tr><td>健康检查</td><td>Liveness / Readiness</td></tr><tr><td>Metrics 暴露</td><td><code>/metrics</code> 端点</td></tr><tr><td>日志规范</td><td>结构化日志、Trace ID 透传</td></tr><tr><td>链路追踪</td><td>OpenTelemetry SDK 集成</td></tr><tr><td>配置中心客户端</td><td>动态拉取配置</td></tr><tr><td>服务注册客户端</td><td>启动时注册、停止时注销</td></tr></tbody></table><p>成熟的框架(Spring Boot、FastAPI、Gin)会把大部分基础设施做成开箱即用,但理解每一块在做什么,才能真正排查问题。</p><h2 id="四、数据层" tabindex="-1">四、数据层 <a class="header-anchor" href="#四、数据层" aria-label="Permalink to &quot;四、数据层&quot;">​</a></h2><p>数据库保存系统的所有状态——用户、订单、权限、审计、配置、任务记录,所有&quot;持久数据&quot;都要落到某种存储。</p><p><img src="`+i+`" alt="数据层选型要按数据形态和访问模式决定"></p><h3 id="按数据特性选存储类型" tabindex="-1">按数据特性选存储类型 <a class="header-anchor" href="#按数据特性选存储类型" aria-label="Permalink to &quot;按数据特性选存储类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>主流选择</th><th>适合存什么</th></tr></thead><tbody><tr><td>关系型数据库</td><td>MySQL、PostgreSQL、Oracle</td><td>用户、订单、权限、审计、配置等结构化数据</td></tr><tr><td>文档数据库</td><td>MongoDB、CouchDB</td><td>字段变化多、嵌套结构、文档型数据</td></tr><tr><td>缓存/键值</td><td>Redis、Memcached</td><td>热点数据、会话、计数器、分布式锁</td></tr><tr><td>列式数据库</td><td>ClickHouse、Cassandra</td><td>大数据分析、时序聚合</td></tr><tr><td>搜索引擎</td><td>Elasticsearch、OpenSearch</td><td>全文检索、日志检索</td></tr><tr><td>时序数据库</td><td>InfluxDB、TimescaleDB、Prometheus</td><td>监控指标、IoT</td></tr><tr><td>图数据库</td><td>Neo4j、JanusGraph</td><td>社交关系、推荐</td></tr><tr><td>向量数据库</td><td>Milvus、Qdrant、pgvector</td><td>AI/向量检索</td></tr></tbody></table><h3 id="mysql-vs-postgresql" tabindex="-1">MySQL vs PostgreSQL <a class="header-anchor" href="#mysql-vs-postgresql" aria-label="Permalink to &quot;MySQL vs PostgreSQL&quot;">​</a></h3><p>国内传统业务系统 MySQL 用得最多——稳定、生态成熟、运维资料多。PostgreSQL 在以下场景上比 MySQL 强:</p><ul><li>复杂 SQL(CTE、窗口函数、递归查询)</li><li>JSON/JSONB 字段(原生支持索引和查询)</li><li>GIS 地理数据(PostGIS 扩展)</li><li>全文检索(原生支持)</li><li>扩展能力(自定义类型、函数、操作符)</li></ul><p><strong>新项目选型时,PostgreSQL 是越来越被推荐的选择</strong>——除非有特别原因(MySQL 团队经验深、强依赖某 MySQL 特性)。</p><h3 id="多数据库共存-是常态" tabindex="-1">多数据库共存:是常态 <a class="header-anchor" href="#多数据库共存-是常态" aria-label="Permalink to &quot;多数据库共存:是常态&quot;">​</a></h3><p>业务系统<strong>同时使用多种数据库</strong>是常态:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MySQL/PostgreSQL → 核心业务数据(用户、订单、权限)</span></span>
<span class="line"><span>Redis            → 缓存、会话、限流、锁</span></span>
<span class="line"><span>Elasticsearch    → 全文搜索、日志检索</span></span>
<span class="line"><span>ClickHouse       → 数据分析、报表</span></span>
<span class="line"><span>MongoDB          → 内容型数据、配置</span></span>
<span class="line"><span>S3/OSS           → 文件、备份</span></span></code></pre></div><p>不同数据各回各家,每种存储用在它最擅长的场景。</p><h3 id="数据库选型的真实考量" tabindex="-1">数据库选型的真实考量 <a class="header-anchor" href="#数据库选型的真实考量" aria-label="Permalink to &quot;数据库选型的真实考量&quot;">​</a></h3><p><strong>数据库选型不只看&quot;能不能存&quot;</strong>,还要看:</p><ul><li><strong>运维生态</strong>:监控、备份恢复、迁移工具是否成熟</li><li><strong>团队熟悉度</strong>:运维难度,故障时谁能修</li><li><strong>索引能力</strong>:能否覆盖业务的查询模式</li><li><strong>权限模型</strong>:是否能满足合规要求</li><li><strong>社区活跃度</strong>:遇到问题能找到答案</li><li><strong>云厂商托管</strong>:是否有 RDS 形式的托管服务</li></ul><p><strong>一个团队没人能运维的数据库,再先进也不能上生产</strong>——出问题时无人能修,损失可能比不上的&quot;先进性&quot;大得多。</p><h2 id="五、缓存与消息队列" tabindex="-1">五、缓存与消息队列 <a class="header-anchor" href="#五、缓存与消息队列" aria-label="Permalink to &quot;五、缓存与消息队列&quot;">​</a></h2><p><img src="`+n+`" alt="缓存加速读取，消息队列削峰异步处理"></p><h3 id="缓存" tabindex="-1">缓存 <a class="header-anchor" href="#缓存" aria-label="Permalink to &quot;缓存&quot;">​</a></h3><p><strong>缓存放在数据库前面,挡住重复查询</strong>。Redis 是最主流的选择——除了缓存,经常顺手承担:</p><ul><li>会话存储(Session)</li><li>限流计数器</li><li>分布式锁</li><li>排行榜(zset)</li><li>实时排重(set)</li><li>简单队列(list / stream)</li></ul><p>一个 Redis 实例能解决一组小问题,所以几乎所有 Web 系统的技术栈里都有 Redis。</p><h3 id="消息队列" tabindex="-1">消息队列 <a class="header-anchor" href="#消息队列" aria-label="Permalink to &quot;消息队列&quot;">​</a></h3><p>消息队列放在服务之间,主要解决两个问题:</p><table tabindex="0"><thead><tr><th>场景</th><th>价值</th></tr></thead><tbody><tr><td>异步执行</td><td>用户请求不用等待耗时操作完成</td></tr><tr><td>削峰填谷</td><td>突发流量被缓冲,后端按自己节奏消费</td></tr><tr><td>解耦</td><td>生产者和消费者互不感知,可独立扩展</td></tr><tr><td>广播</td><td>一条消息多个下游消费</td></tr></tbody></table><h3 id="主流消息队列" tabindex="-1">主流消息队列 <a class="header-anchor" href="#主流消息队列" aria-label="Permalink to &quot;主流消息队列&quot;">​</a></h3><table tabindex="0"><thead><tr><th>消息系统</th><th>特点</th><th>适用场景</th></tr></thead><tbody><tr><td>RabbitMQ</td><td>AMQP 协议,功能丰富,可靠投递</td><td>任务分发、传统业务队列</td></tr><tr><td>Kafka</td><td>高吞吐、日志型设计、分区有序</td><td>日志流、事件流、数据管道</td></tr><tr><td>RocketMQ</td><td>阿里出品,事务消息、延迟消息</td><td>国内电商、金融业务</td></tr><tr><td>Pulsar</td><td>计算存储分离</td><td>新兴选择,云原生</td></tr><tr><td>Redis Stream/List</td><td>轻量,与 Redis 共用</td><td>内部小任务,不想新增组件</td></tr><tr><td>NATS</td><td>轻量、低延迟</td><td>微服务通信、IoT</td></tr></tbody></table><h3 id="异步处理的标准模式" tabindex="-1">异步处理的标准模式 <a class="header-anchor" href="#异步处理的标准模式" aria-label="Permalink to &quot;异步处理的标准模式&quot;">​</a></h3><p>典型场景:用户点击&quot;导出报表&quot;</p><p><strong>同步方案的问题</strong>:接口同步等待生成,可能需要数十秒到数分钟,用户体验差,超时风险高。</p><p><strong>异步方案</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 用户请求导出 → 接口立即返回任务 ID</span></span>
<span class="line"><span>2. 生成任务推入消息队列</span></span>
<span class="line"><span>3. 后台 worker 消费队列,真正生成报表</span></span>
<span class="line"><span>4. 生成完毕,更新任务状态,通知用户</span></span>
<span class="line"><span>5. 用户通过任务 ID 查询状态、下载结果</span></span></code></pre></div><p><strong>关键认知:&quot;请求已接收&quot;(接口成功)≠ &quot;任务已完成&quot;(报表已生成)</strong>。</p><p>排查这类问题时,要看:</p><ul><li>任务状态机:任务当前处于什么状态</li><li>队列积压:有没有消息没被消费</li><li>消费失败:重试次数、失败原因</li><li>消费者实例:是否在运行、有没有崩溃</li></ul><h2 id="六、文件存储" tabindex="-1">六、文件存储 <a class="header-anchor" href="#六、文件存储" aria-label="Permalink to &quot;六、文件存储&quot;">​</a></h2><p>上传的文件(头像、附件、图片)、备份包、日志归档、构建产物——<strong>这些不适合长期绑在某台应用服务器的本地目录上</strong>。</p><h3 id="对象存储-主流方案" tabindex="-1">对象存储:主流方案 <a class="header-anchor" href="#对象存储-主流方案" aria-label="Permalink to &quot;对象存储:主流方案&quot;">​</a></h3><p>按 bucket(桶)和 object key(对象键)组织文件,通过 HTTP API 访问。主流选择:</p><table tabindex="0"><thead><tr><th>方案</th><th>类型</th></tr></thead><tbody><tr><td>AWS S3</td><td>云厂商(行业标准)</td></tr><tr><td>阿里云 OSS</td><td>云厂商</td></tr><tr><td>腾讯云 COS</td><td>云厂商</td></tr><tr><td>MinIO</td><td>自建,兼容 S3 API</td></tr><tr><td>Ceph RGW</td><td>自建,大规模</td></tr></tbody></table><h3 id="文件元数据与对象解耦" tabindex="-1">文件元数据与对象解耦 <a class="header-anchor" href="#文件元数据与对象解耦" aria-label="Permalink to &quot;文件元数据与对象解耦&quot;">​</a></h3><p>后端数据库里<strong>只保存文件元数据</strong>,不直接存文件本身:</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>file_name</code></td><td>用户看到的原始文件名</td></tr><tr><td><code>size</code></td><td>文件大小</td></tr><tr><td><code>mime_type</code></td><td>MIME 类型</td></tr><tr><td><code>owner_id</code></td><td>归属用户/对象</td></tr><tr><td><code>object_key</code></td><td>对象存储中的真实路径</td></tr><tr><td><code>upload_time</code></td><td>上传时间</td></tr><tr><td><code>etag</code></td><td>文件指纹,校验完整性</td></tr></tbody></table><p>数据库存元数据,对象存储存实际文件,各自负责擅长的部分。</p><h3 id="为什么不能放本地目录" tabindex="-1">为什么不能放本地目录 <a class="header-anchor" href="#为什么不能放本地目录" aria-label="Permalink to &quot;为什么不能放本地目录&quot;">​</a></h3><p>应用扩为多实例时本地存储立即失效:</p><ul><li>用户上传头像到 <code>app-01</code>,文件保存在 <code>app-01:/data/uploads/</code></li><li>下次访问头像,请求被分到 <code>app-02</code></li><li><code>app-02</code> 本地没有这个文件 → 404</li></ul><p>对象存储让多个实例访问同一份文件,根本解决这个问题。同时:</p><ul><li>对象存储自身有副本和容灾,可靠性高</li><li>与应用实例解耦,实例随时可重建</li><li>公网访问可直接走 CDN,加速分发</li></ul><h2 id="七、入口层" tabindex="-1">七、入口层 <a class="header-anchor" href="#七、入口层" aria-label="Permalink to &quot;七、入口层&quot;">​</a></h2><p>入口层负责<strong>接收外部请求,转发到正确的内部服务</strong>。这一层组件较多,各司其职。</p><h3 id="入口层组件" tabindex="-1">入口层组件 <a class="header-anchor" href="#入口层组件" aria-label="Permalink to &quot;入口层组件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>组件</th><th>主要职责</th></tr></thead><tbody><tr><td>CDN</td><td>静态资源全球分发、缓存、抗 DDoS</td></tr><tr><td>WAF</td><td>安全过滤(SQL 注入、XSS、爬虫)</td></tr><tr><td>云负载均衡(SLB/ALB)</td><td>公网入口、四层/七层转发</td></tr><tr><td>Nginx</td><td>反向代理、TLS 终止、限流、静态资源</td></tr><tr><td>HAProxy</td><td>高性能负载均衡(四层/七层)</td></tr><tr><td>Ingress</td><td>K8s 集群 HTTP/HTTPS 入口</td></tr><tr><td>API 网关(Kong/APISIX/Higress)</td><td>认证、路由、限流、协议转换、API 管理</td></tr></tbody></table><h3 id="完整入口链路" tabindex="-1">完整入口链路 <a class="header-anchor" href="#完整入口链路" aria-label="Permalink to &quot;完整入口链路&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户 → DNS → CDN → WAF → 云 LB → Ingress/Nginx → 后端服务</span></span></code></pre></div><p>每一层都可能成为问题源,出现 502、504、403、证书错误时,<strong>入口层是第一处检查点</strong>。</p><p>入口日志能看到:请求是否进入、转发到哪个后端、后端返回状态、耗时分布。<strong>80% 的&quot;用户访问异常&quot;问题,从入口日志开始查最快</strong>。</p><h3 id="api-网关-vs-nginx" tabindex="-1">API 网关 vs Nginx <a class="header-anchor" href="#api-网关-vs-nginx" aria-label="Permalink to &quot;API 网关 vs Nginx&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>Nginx</th><th>API 网关(Kong/APISIX)</th></tr></thead><tbody><tr><td>主要用途</td><td>反向代理 + 静态资源</td><td>API 管理 + 服务路由</td></tr><tr><td>配置方式</td><td>配置文件</td><td>控制台 / API</td></tr><tr><td>插件能力</td><td>较少(需要 Lua)</td><td>丰富(认证、限流、转换、日志等几十种)</td></tr><tr><td>动态路由</td><td>不支持热更新(reload 切换)</td><td>实时更新</td></tr><tr><td>服务发现集成</td><td>较少</td><td>原生支持</td></tr><tr><td>适用场景</td><td>简单代理、静态资源</td><td>微服务 API 管理</td></tr></tbody></table><p>简单场景用 Nginx 足够;微服务架构、API 管理需求复杂的场景才需要 API 网关。</p><h2 id="八、可观测与发布" tabindex="-1">八、可观测与发布 <a class="header-anchor" href="#八、可观测与发布" aria-label="Permalink to &quot;八、可观测与发布&quot;">​</a></h2><h3 id="可观测组件" tabindex="-1">可观测组件 <a class="header-anchor" href="#可观测组件" aria-label="Permalink to &quot;可观测组件&quot;">​</a></h3><p>可观测组件负责&quot;看见&quot;系统状态,出问题时能定位:</p><table tabindex="0"><thead><tr><th>能力</th><th>主流选择</th></tr></thead><tbody><tr><td>指标采集和存储</td><td>Prometheus、VictoriaMetrics、Mimir</td></tr><tr><td>指标看板</td><td>Grafana(几乎是标准)</td></tr><tr><td>告警</td><td>Alertmanager、Nightingale(夜莺)</td></tr><tr><td>日志收集</td><td>Filebeat、Fluentd、Promtail、Vector</td></tr><tr><td>日志存储 / 查询</td><td>Loki、Elasticsearch、OpenSearch、ClickHouse</td></tr><tr><td>链路追踪</td><td>OpenTelemetry、Jaeger、SkyWalking、Tempo</td></tr><tr><td>APM(应用性能管理)</td><td>SkyWalking、Datadog、New Relic</td></tr></tbody></table><h3 id="发布组件" tabindex="-1">发布组件 <a class="header-anchor" href="#发布组件" aria-label="Permalink to &quot;发布组件&quot;">​</a></h3><p>发布组件负责把代码变成线上版本:</p><table tabindex="0"><thead><tr><th>能力</th><th>主流选择</th></tr></thead><tbody><tr><td>代码仓库</td><td>GitLab、GitHub、Gitea、Bitbucket</td></tr><tr><td>CI(持续集成)</td><td>GitLab CI、Jenkins、GitHub Actions、Drone、Tekton</td></tr><tr><td>镜像仓库</td><td>Harbor、阿里云 ACR、Docker Hub</td></tr><tr><td>CD / GitOps</td><td>Argo CD、Flux、Spinnaker</td></tr><tr><td>配置管理</td><td>Ansible、Terraform、Pulumi</td></tr></tbody></table><h2 id="九、一套典型的内部技术栈" tabindex="-1">九、一套典型的内部技术栈 <a class="header-anchor" href="#九、一套典型的内部技术栈" aria-label="Permalink to &quot;九、一套典型的内部技术栈&quot;">​</a></h2><p>把所有层串起来,<strong>一套典型的中型公司内部技术栈</strong>大概是:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>前端       Vue 或 React + Vite + Element Plus / Ant Design</span></span>
<span class="line"><span>后端       Spring Boot(Java)或 FastAPI(Python)或 Gin(Go)</span></span>
<span class="line"><span>数据库     MySQL 或 PostgreSQL + Redis 缓存</span></span>
<span class="line"><span>搜索       Elasticsearch(可选)</span></span>
<span class="line"><span>文件       MinIO 或 云 OSS</span></span>
<span class="line"><span>消息       RabbitMQ 或 Kafka(可选)</span></span>
<span class="line"><span>入口       Nginx + 云 SLB</span></span>
<span class="line"><span>容器       Docker</span></span>
<span class="line"><span>编排       Kubernetes</span></span>
<span class="line"><span>监控       Prometheus + Grafana + Alertmanager</span></span>
<span class="line"><span>日志       Loki + Grafana,或 ELK</span></span>
<span class="line"><span>追踪       Jaeger 或 SkyWalking</span></span>
<span class="line"><span>CI/CD      GitLab CI + Harbor + Argo CD</span></span>
<span class="line"><span>配置       Apollo 或 Nacos</span></span>
<span class="line"><span>注册中心   Nacos 或 Consul(微服务场景)</span></span></code></pre></div><p>这不是唯一答案,只是常见的位置关系。换其中任何一个组件(Vue → Svelte、MySQL → TiDB、Prometheus → VictoriaMetrics),只要功能定位相同,其他部分基本不需要变。</p><h3 id="选型时的核心问题" tabindex="-1">选型时的核心问题 <a class="header-anchor" href="#选型时的核心问题" aria-label="Permalink to &quot;选型时的核心问题&quot;">​</a></h3><p>接触任意新技术栈时,问自己这几个问题:</p><ol><li><strong>它解决什么问题?</strong> — 在系统的哪一层?</li><li><strong>它替代什么?</strong> — 与已有组件的关系?</li><li><strong>它的运维成本?</strong> — 谁能维护、出问题谁能修?</li><li><strong>它的故障域?</strong> — 挂了影响范围多大?</li><li><strong>它的退出成本?</strong> — 如果不合适,迁出去难不难?</li></ol><p><strong>能跑起来是一回事,出问题能排查、能演进、能替换是另一回事</strong>——后者才是技术选型的真正考验。</p><h2 id="十、技术栈的演进规律" tabindex="-1">十、技术栈的演进规律 <a class="header-anchor" href="#十、技术栈的演进规律" aria-label="Permalink to &quot;十、技术栈的演进规律&quot;">​</a></h2><p>技术栈不是一成不变的——业务规模、团队能力、流量特点都在变化,技术栈也要跟着演进。常见演进路径:</p><p><img src="`+l+`" alt="技术栈随着问题规模从简单到分层演进"></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>启动期       单机部署 + 单数据库 + 简单 Web 框架</span></span>
<span class="line"><span>成长期       负载均衡 + 多实例 + Redis 缓存 + CDN</span></span>
<span class="line"><span>扩张期       数据库主从 + 消息队列 + 监控告警 + 日志聚合</span></span>
<span class="line"><span>成熟期       微服务 + K8s + 完整可观测 + CI/CD</span></span>
<span class="line"><span>大型化       服务网格 + 多机房 + 分库分表 + 流量治理</span></span></code></pre></div><p><strong>每一步演进都要解决&quot;业务真实痛点&quot;</strong>——不要为了&quot;看起来现代化&quot;提前引入复杂度。Kubernetes 不是必需,微服务不是必需,服务网格更不是必需。架构演进的核心原则:<strong>业务驱动技术演进,而不是技术驱动架构升级</strong>。</p>`,119)])])}const A=a(o,[["render",p]]);export{E as __pageData,A as default};
